<?php
// api/users.php - SECURE CORS configuration

class CorsHandler {
    // Explicitly whitelist allowed origins
    private const ALLOWED_ORIGINS = [
        'https://myapp.com',
        'https://www.myapp.com',
        'https://admin.myapp.com'
