Great questions! Dynamic subdomain support requires careful regex validation, and proper preflight handling is crucial for security and performance. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security headers
app.use(helmet());

// CORS Configuration with dynamic subdomain support
class CorsHandler {
  constructor(options) {
    this.baseDomain = options.baseDomain;
    this.staticOrigins = new Set(options.staticOrigins || []);
    this.allowSubdomains = options.allowSubdomains || false;
    this.subdomainPattern = this.allowSubdomains 
      ? new RegExp(`^https:\/\/([a-z0-9-]+\.)?${this.escapeRegex(this.baseDomain)}$`)
      : null;
  }

  escapeRegex(string) {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  isOriginAllowed(origin) {
    if (!origin) return false;

    // Check static whitelist first
    if (this.staticOrigins.has(origin)) {
      return true;
    }

    // Check subdomain pattern if enabled
    if (this.subdomainPattern && this.subdomainPattern.test(origin)) {
      return true;
    }

    return false;
  }

  middleware() {
    return (req, res, next) => {
      const origin = req.headers.origin;

      // Handle preflight requests
      if (req.method === 'OPTIONS') {
        return this.handlePreflight(req, res, origin);
      }

      // Handle actual requests
      this.handleActualRequest(req, res, next, origin);
    };
  }

  handlePreflight(req, res, origin) {
    if (this.isOriginAllowed(origin)) {
      res.setHeader('Access-Control-Allow-Origin', origin);
      res.setHeader('Access-Control-Allow-Credentials', 'true');
      res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, PATCH');
      res.setHeader('Access-Control-Allow-Headers', 
        'Content-Type, Authorization, X-Requested-With, X-CSRF-Token');
      res.setHeader('Access-Control-Max-Age', '86400');
      res.setHeader('Vary', 'Origin');
      return res.status(204).end();
    }

    // Log blocked preflight
    console.warn(`CORS preflight blocked: ${origin} -> ${req.path}`);
    return res.status(403).json({ error: 'CORS policy violation' });
  }

  handleActualRequest(req, res, next, origin) {
    if (!origin) {
      // No origin header - could be same-origin, server-to-server, or curl
      // Decide based on your security requirements
      return next();
    }

    if (this.isOriginAllowed(origin)) {
      res.setHeader('Access-Control-Allow-Origin', origin);
      res.setHeader('Access-Control-Allow-Credentials', 'true');
      res.setHeader('Vary', 'Origin');
      return next();
    }

    // Log and block unauthorized origin
    console.error(`CORS violation: ${origin} attempted access to ${req.path}`);
    return res.status(403).json({ error: 'Origin not allowed' });
  }
}

// Production configuration
const corsHandler = new CorsHandler({
  baseDomain: 'mycompany.com',
  allowSubdomains: true,
  staticOrigins: [
    'https://mycompany.com',
    'https://www.mycompany.com',
    'https://app.mycompany.com',
    'https://api.mycompany.com'
  ]
});

// Add localhost only in development
if (process.env.NODE_ENV === 'development') {
  corsHandler.staticOrigins.add('http://localhost:3000');
  corsHandler.staticOrigins.add('http://localhost:8080');
}

app.use(corsHandler.middleware());

// Rate limiting for API endpoints
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    console.warn(`Rate limit exceeded: ${req.ip}`);
    res.status(429).json({ error: 'Too many requests' });
  }
});

app.use('/api/', apiLimiter);

// Sensitive endpoints with additional CSRF protection
app.post('/api/user/settings', (req, res) => {
  // Verify CSRF token for state-changing operations
  const csrfToken = req.headers['x-csrf-token'];
  if (!csrfToken || csrfToken !== req.session.csrfToken) {
    return res.status(403).json({ error: 'Invalid CSRF token' });
  }

  // Process request
  res.json({ success: true });
});

// Health check (no CORS restrictions needed)
app.get('/health', (req, res) => {
  res.json({ status: 'healthy' });
});

// Error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(process.env.PORT || 3000, () => {
  console.log(`Server running in ${process.env.NODE_ENV || 'development'} mode`);
});
```

**Defense in Depth Layers**:

1. **Origin Validation Layer**:
```javascript
// Strict regex for subdomain matching - prevents regex injection
const subdomainPattern = /^https:\/\/([a-z0-9-]+\.)?mycompany\.com$/;
// Only matches: https://mycompany.com, https://app.mycompany.com
// Does NOT match: https://evil-mycompany.com, https://mycompany.com.evil.com
```

2. **Preflight Caching Layer**:
```javascript
// Cache preflight responses to reduce server load
res.setHeader('Access-Control-Max-Age', '86400'); // 24 hours
res.setHeader('Vary', 'Origin'); // Critical: tells browsers/CDNs to cache per-origin
```

3. **CSRF Token Layer**:
```javascript
// For state-changing operations, require CSRF token even with CORS
const crypto = require('crypto');

app.get('/api/csrf-token', (req, res) => {
  const token = crypto.randomBytes(32).toString('hex');
  req.session.csrfToken = token;
  res.json({ csrfToken: token });
});
```

**Additional Protections**:

- **Vary: Origin header**: Essential for proper caching behavior with CDNs; prevents one origin's response from being served to another
- **No wildcard with credentials**: Browsers block `Access-Control-Allow-Origin: *` when `credentials: include` is used - but don't rely on this, implement proper validation
- **Subdomain regex anchoring**: Always anchor regex patterns (^ and $) to prevent bypass via attacker domains like `evil-mycompany.com`
- **Separate public/private APIs**: Public APIs can use broader CORS; private APIs with user data need strict origin validation
- **Security monitoring**: Log all CORS violations for security analysis and potential attack detection
- **SameSite cookies**: Use `SameSite=Strict` or `SameSite=Lax` cookies as additional protection against cross-site attacks

