**SECURE VERSION**:

```java
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
import org.springframework.web.filter.CorsFilter;

import java.util.Arrays;
import java.util.List;

@Configuration
public class SecureCorsConfig {

    @Value("${app.cors.allowed-origins}")
    private String[] allowedOrigins;

    private static final List<String> ALLOWED_METHODS = Arrays.asList(
        "GET", "POST", "PUT", "DELETE", "OPTIONS"
    );

    private static final List<String> ALLOWED_HEADERS = Arrays.asList(
        "Authorization", "Content-Type", "X-Requested-With", "X-CSRF-Token"
    );

    @Bean
    public CorsFilter corsFilter() {
        CorsConfiguration config = new CorsConfiguration();

        // SECURE: Explicitly whitelist trusted origins
        for (String origin : allowedOrigins) {
            config.addAllowedOrigin(origin.trim());
        }

        // SECURE: Only allow necessary HTTP methods
        config.setAllowedMethods(ALLOWED_METHODS);

        // SECURE: Only allow required headers
        config.setAllowedHeaders(ALLOWED_HEADERS);

        // SECURE: Limit exposed headers
        config.setExposedHeaders(Arrays.asList("X-Request-Id"));

        // Only enable if your app requires cookies/auth headers
        config.setAllowCredentials(true);

        // Cache preflight for 1 hour
        config.setMaxAge(3600L);

        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/api/**", config);
        return new CorsFilter(source);
    }
}
```

**Key Security Controls**:
- **Explicit origin whitelist**: Only trusted domains (your frontend URLs) can access the API
- **Limited HTTP methods**: Reduces attack surface by restricting to necessary methods
- **Limited headers**: Prevents header injection attacks by whitelisting required headers
- **Scoped configuration**: Only applies to `/api/**` paths, not entire application

Great questions! Production CORS configuration needs environment-aware origin handling and careful subdomain validation. Attackers often exploit wildcard subdomain patterns or origin reflection vulnerabilities.

**PRODUCTION PATTERN**:

```java
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.core.env.Environment;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
import org.springframework.web.filter.CorsFilter;

import javax.servlet.http.HttpServletRequest;
import java.util.Arrays;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.regex.Pattern;

@Configuration
public class ProductionCorsConfig {

    private static final Logger logger = LoggerFactory.getLogger(ProductionCorsConfig.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    private final Environment environment;

    // Production origins from secure configuration
    @Value("${cors.allowed.origins.production:}")
    private String productionOrigins;

    @Value("${cors.allowed.origins.staging:}")
    private String stagingOrigins;

    @Value("${cors.allowed.origins.development:http://localhost:3000,http://localhost:8080}")
    private String developmentOrigins;

    @Value("${cors.allowed.subdomain.pattern:}")
    private String allowedSubdomainPattern;

    public ProductionCorsConfig(Environment environment) {
        this.environment = environment;
    }

    @Bean
    public CorsFilter corsFilter() {
        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();

        // Public API endpoints - no credentials
        CorsConfiguration publicConfig = createPublicCorsConfig();
        source.registerCorsConfiguration("/api/public/**", publicConfig);

        // Authenticated API endpoints - strict origin validation
        CorsConfiguration authenticatedConfig = createAuthenticatedCorsConfig();
        source.registerCorsConfiguration("/api/v1/**", authenticatedConfig);

        // Admin endpoints - most restrictive
        CorsConfiguration adminConfig = createAdminCorsConfig();
        source.registerCorsConfiguration("/api/admin/**", adminConfig);

        return new CorsFilter(source);
    }

    private CorsConfiguration createAuthenticatedCorsConfig() {
        CorsConfiguration config = new CorsConfiguration();

        Set<String> origins = getEnvironmentSpecificOrigins();
        origins.forEach(origin -> {
            config.addAllowedOrigin(origin);
            logger.debug("Added allowed origin: {}", origin);
        });

        // SECURE: Enable subdomain pattern matching with validation
        if (!allowedSubdomainPattern.isEmpty()) {
            config.addAllowedOriginPattern(allowedSubdomainPattern);
        }

        config.setAllowedMethods(Arrays.asList("GET", "POST", "PUT", "DELETE", "PATCH", "OPTIONS"));
        config.setAllowedHeaders(Arrays.asList(
            "Authorization",
            "Content-Type",
            "X-Requested-With",
            "X-CSRF-Token",
            "X-Request-Id"
        ));
        config.setExposedHeaders(Arrays.asList("X-Request-Id", "X-RateLimit-Remaining"));
        config.setAllowCredentials(true);
        config.setMaxAge(3600L);

        return config;
    }

    private CorsConfiguration createPublicCorsConfig() {
        CorsConfiguration config = new CorsConfiguration();
        // Public endpoints can have broader access but NO credentials
        config.addAllowedOriginPattern("https://*.trusted-domain.com");
        config.setAllowedMethods(Arrays.asList("GET", "OPTIONS"));
        config.setAllowedHeaders(Arrays.asList("Content-Type", "X-Request-Id"));
        config.setAllowCredentials(false); // CRITICAL: No credentials for public
        config.setMaxAge(86400L);
        return config;
    }

    private CorsConfiguration createAdminCorsConfig() {
        CorsConfiguration config = new CorsConfiguration();
        // Admin: Only specific admin domain
        String activeProfile = getActiveProfile();
        if ("production".equals(activeProfile)) {
            config.addAllowedOrigin("https://admin.company.com");
        } else {
            config.addAllowedOrigin("http://localhost:3001");
        }
        config.setAllowedMethods(Arrays.asList("GET", "POST", "PUT", "DELETE", "OPTIONS"));
        config.setAllowedHeaders(Arrays.asList("Authorization", "Content-Type", "X-Admin-Token"));
        config.setAllowCredentials(true);
        config.setMaxAge(1800L); // Shorter cache for admin
        return config;
    }

    private Set<String> getEnvironmentSpecificOrigins() {
        Set<String> origins = new HashSet<>();
        String activeProfile = getActiveProfile();

        switch (activeProfile) {
            case "production":
                parseAndAddOrigins(origins, productionOrigins);
                auditLogger.info("CORS configured for PRODUCTION with {} origins", origins.size());
                break;
            case "staging":
                parseAndAddOrigins(origins, stagingOrigins);
                logger.info("CORS configured for STAGING");
                break;
            default:
                parseAndAddOrigins(origins, developmentOrigins);
                logger.warn("CORS configured for DEVELOPMENT - not suitable for production");
        }

        if (origins.isEmpty()) {
            throw new IllegalStateException(
                "No CORS origins configured for profile: " + activeProfile
            );
        }

        return origins;
    }

    private void parseAndAddOrigins(Set<String> origins, String originString) {
        if (originString == null || originString.trim().isEmpty()) {
            return;
        }

        for (String origin : originString.split(",")) {
            String trimmed = origin.trim();
            if (isValidOrigin(trimmed)) {
                origins.add(trimmed);
            } else {
                logger.error("Invalid origin rejected: {}", trimmed);
            }
        }
    }

    private boolean isValidOrigin(String origin) {
        // SECURITY: Validate origin format
        if (origin == null || origin.isEmpty()) {
            return false;
        }

        // Must be HTTPS in production (except localhost for dev)
        if ("production".equals(getActiveProfile())) {
            if (!origin.startsWith("https://")) {
                logger.error("Production origin must use HTTPS: {}", origin);
                return false;
            }
        }

        // Reject wildcard and dangerous patterns
        if (origin.equals("*") || origin.contains("null")) {
            logger.error("Dangerous origin pattern rejected: {}", origin);
            return false;
        }

        // Validate URL format
        Pattern urlPattern = Pattern.compile(
            "^https?://[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(\\.[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*(:[0-9]{1,5})?$"
        );
        return urlPattern.matcher(origin).matches();
    }

    private String getActiveProfile() {
        String[] profiles = environment.getActiveProfiles();
        return profiles.length > 0 ? profiles[0] : "development";
    }
}
```

**Defense in Depth Layers**:

1. **Environment-specific configuration**:
```java
// application-production.yml
cors:
  allowed:
    origins:
      production: "https://app.company.com,https://www.company.com"
    subdomain:
      pattern: "https://*.company.com"
```

2. **Request-level origin validation filter**:
```java
@Component
@Order(Ordered.HIGHEST_PRECEDENCE)
public class CorsAuditFilter extends OncePerRequestFilter {

    private static final Logger auditLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                    HttpServletResponse response,
                                    FilterChain chain) throws ServletException, IOException {

        String origin = request.getHeader("Origin");
        String referer = request.getHeader("Referer");

        // Log all cross-origin requests for security monitoring
        if (origin != null && !origin.isEmpty()) {
            auditLogger.info("CORS_REQUEST origin={} path={} method={} referer={} ip={}",
                origin,
                request.getRequestURI(),
                request.getMethod(),
                referer,
                request.getRemoteAddr()
            );
        }

        chain.doFilter(request, response);
    }
}
```

3. **Security headers for additional protection**:
```java
@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .headers(headers -> headers
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives("default-src 'self'; script-src 'self'; frame-ancestors 'none'")
                )
                .frameOptions(frame -> frame.deny())
                .xssProtection(xss -> xss.enable())
                .contentTypeOptions(contentType -> {})
                .referrerPolicy(referrer -> referrer
                    .policy(ReferrerPolicyHeaderWriter.ReferrerPolicy.STRICT_ORIGIN_WHEN_CROSS_ORIGIN)
                )
            );
        return http.build();
    }
}
```

**Additional Protections**:
- **Never reflect Origin header directly**: Always validate against whitelist before setting Access-Control-Allow-Origin
- **Use allowedOriginPatterns carefully**: `*.company.com` is safer than `*.com`, but validate pattern doesn't match attacker-controlled subdomains
- **Monitor CORS violations**: Log rejected origins and set up alerts for unusual patterns
- **Separate configs by sensitivity**: Public APIs can be more permissive, authenticated endpoints must be strict
- **Fail closed**: If origin configuration is missing or invalid, reject all cross-origin requests
